95:export async function uploadAttachmentFile(file, bookingId, type = 'photo') {
96:  const sizeBytes = file.size;
97:  const buf = await file.arrayBuffer();
98:  const hashBuf = await crypto.subtle.digest('SHA-256', buf);
99:  const hashArray = Array.from(new Uint8Array(hashBuf));
100:  const hex = hashArray.map((b) => b.toString(16).padStart(2, '0')).join('');
101:  const checksum = hex;
102:  const fingerprint = hex;
103:
104:  const initResp = await attachmentInit({ bookingId, type, sizeBytes, checksum, fingerprint });
105:  // If server deduplicated the upload, initResp may include { deduplicated: true, attachment: { id: ... } }
106:  if (initResp && initResp.deduplicated) {
107:    const existing = initResp.attachment || initResp.att || initResp;
108:    const existingId = existing && (existing.id || existing.ID || existing.uploadId);
109:    if (existingId) return existingId;
110:  }
111:  const uploadId = initResp.uploadId || initResp.uploadID || initResp.UploadID || initResp.uploadId;
112:  // chunk size ~512KB
113:  const chunkSize = 512 * 1024;
114:  for (let offset = 0; offset < buf.byteLength; offset += chunkSize) {
115:    const slice = buf.slice(offset, Math.min(offset + chunkSize, buf.byteLength));
116:    const u8 = new Uint8Array(slice);
117:    let binary = '';
118:    for (let i = 0; i < u8.length; i++) binary += String.fromCharCode(u8[i]);
119:    const chunkBase64 = btoa(binary);
120:    await attachmentChunk({ uploadId, chunkBase64 });
121:  }
122:  await attachmentComplete({ uploadId });
123:  return uploadId;
124:}
