57:func startNightlyBackupScheduler(st store.Repository, logger *slog.Logger) {
58:	go func() {
59:		for {
60:			now := time.Now()
61:			next := time.Date(now.Year(), now.Month(), now.Day(), 2, 0, 0, 0, now.Location())
62:			if !next.After(now) {
63:				next = next.Add(24 * time.Hour)
64:			}
65:			time.Sleep(time.Until(next))
66:			job := models.BackupJob{
67:				ID:        uuid.NewString(),
68:				Type:      "backup",
69:				Status:    "running",
70:				CreatedAt: time.Now().UTC(),
71:			}
72:			st.SaveBackupJob(job)
73:			cmd := exec.Command("sh", "scripts/backup.sh")
74:			if out, err := cmd.CombinedOutput(); err != nil {
75:				job.Status = "failed"
76:				job.Error = string(out)
77:				job.FinishedAt = time.Now().UTC()
78:				st.SaveBackupJob(job)
79:				logger.Error("nightly backup failed", "error", err)
80:				continue
81:			}
82:			job.Status = "completed"
83:			job.Artifact = "local-backup"
84:			job.FinishedAt = time.Now().UTC()
85:			st.SaveBackupJob(job)
86:			logger.Info("nightly backup completed")
87:		}
88:	}()
