  block, err := aes.NewCipher(keyB)
  if err != nil {
    fmt.Println("cipher error:", err)
    os.Exit(1)
  }
  gcm, err := cipher.NewGCM(block)
  if err != nil {
    fmt.Println("gcm error:", err)
    os.Exit(1)
  }

  nonceSize := gcm.NonceSize()
  nonce := raw[:nonceSize]
  ciphertext := raw[nonceSize:]

